    },
    {
        "type": "function",
        "function": {
            "name": "waehrung_umrechnen",
            "description": "Betrag von einer Währung in eine andere umrechnen.",
            "parameters": {
                "type": "object",
                "properties": {
                    "betrag": {"type": "number"},
                    "von":    {"type": "string", "description": "z.B. EUR"},
                    "nach":   {"type": "string", "description": "z.B. USD"}
                },
                "required": ["betrag", "von", "nach"]
            }
        }
    }
]

# Dispatch-Tabelle: Name → Funktion
def waehrung_umrechnen(betrag: float, von: str, nach: str) -> str:
    kurs = 1.09 if von == "EUR" and nach == "USD" else 0.92
    return f"{betrag} {von} = {betrag * kurs:.2f} {nach}"

DISPATCH = {
    "aktien_kurs_abfragen": aktien_kurs_abfragen,
    "waehrung_umrechnen":   waehrung_umrechnen,
}

# Alle parallelen Tool-Calls in einer Schleife abarbeiten
response = client.chat.completions.create(
    model="gpt-4o-mini",
    messages=[{"role": "user", "content":
        "Was kostet BMW.DE und wie viel sind 95 EUR in USD?"}],
    tools=tools
)
assistant_msg = response.choices[0].message
messages = [{"role": "user", "content": "..."},
            assistant_msg]

for tool_call in assistant_msg.tool_calls:
    fn   = DISPATCH[tool_call.function.name]
    args = json.loads(tool_call.function.arguments)
    out  = fn(**args)
    messages.append({
        "role": "tool",
        "tool_call_id": tool_call.id,
        "content": out
    })

final = client.chat.completions.create(
    model="gpt-4o-mini", messages=messages, tools=tools
)
print(final.choices[0].message.content)

import json, traceback
from typing import Any

def dispatch_tool(tool_call, dispatch_table: dict) -> str:
    """
    Führt einen Tool-Call aus und gibt immer einen String zurück –
    auch bei Fehlern, damit der Agent-Loop nicht abbricht.
    """
    name = tool_call.function.name

    if name not in dispatch_table:
        return json.dumps({"error": f"Unbekanntes Tool: {name}"})

    try:
        args: dict[str, Any] = json.loads(tool_call.function.arguments)
    except json.JSONDecodeError as e:
        return json.dumps({"error": f"Ungültige Argumente: {e}"})

    try:
        result = dispatch_table[name](**args)
        return str(result)
    except TypeError as e:
        # Falsche Parameter (z.B. fehlendes Required-Argument)
        return json.dumps({"error": f"Parameter-Fehler: {e}"})
    except Exception:
        # Alle anderen Laufzeitfehler loggen, Agent nicht crashen
        traceback.print_exc()
        return json.dumps({"error": "Interner Fehler – Tool konnte nicht ausgeführt werden."})
